  1→/**
  2→ * BOMRepository — CRUD operations for BOM and BOMItem models
  3→ *
  4→ * BOM has @unique projectId (1 BOM per project). BOMItem is a child with onDelete: Cascade.
  5→ * Follows CounterpartyRepository pattern: singleton, manual UUID, manual updatedAt.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type { BOM, BOMItem, Prisma } from '@prisma/client';
 10→import { randomUUID } from 'node:crypto';
 11→
 12→/**
 13→ * BOM creation input — projectId is required, items are optional
 14→ */
 15→export type BOMCreateInput = {
 16→  projectId: string;
 17→  sourceFileId?: string;
 18→  items?: (Omit<Prisma.BOMItemUncheckedCreateInput, 'id' | 'bomId' | 'createdAt' | 'updatedAt'> &
 19→    Partial<Pick<Prisma.BOMItemUncheckedCreateInput, 'id' | 'updatedAt'>>)[];
 20→};
 21→
 22→/**
 23→ * BOM update input
 24→ */
 25→export type BOMUpdateInput = Prisma.BOMUncheckedUpdateInput;
 26→
 27→/**
 28→ * BOMItem creation input
 29→ */
 30→export type BOMItemCreateInput = Omit<Prisma.BOMItemUncheckedCreateInput, 'id' | 'createdAt' | 'updatedAt'> &
 31→  Partial<Pick<Prisma.BOMItemUncheckedCreateInput, 'id' | 'updatedAt'>>;
 32→
 33→/**
 34→ * BOMItem update input
 35→ */
 36→export type BOMItemUpdateInput = Prisma.BOMItemUncheckedUpdateInput & {
 37→  updatedAt?: never; // updatedAt is always set by the repository
 38→};
 39→
 40→/**
 41→ * Repository for BOM and BOMItem CRUD operations
 42→ */
 43→export class BOMRepository {
 44→  // ─── BOM CRUD ────────────────────────────────────────────
 45→
 46→  /**
 47→   * Create a BOM with auto-generated id, status='draft', version=1, updatedAt
 48→   * Optionally creates nested BOMItems via the `items` field
 49→   */
 50→  async create(data: BOMCreateInput): Promise<BOM & { BOMItem?: BOMItem[] }> {
 51→    const { items, ...bomData } = data;
 52→
 53→    return prisma.bOM.create({
 54→      data: {
 55→        ...bomData,
 56→        id: randomUUID(),
 57→        updatedAt: new Date(),
 58→        status: 'draft',
 59→        version: 1,
 60→        BOMItem: items
 61→          ? {
 62→              create: items.map((item, index) => ({
 63→                ...item,
 64→                id: item.id ?? randomUUID(),
 65→                rowNumber: item.rowNumber ?? index + 1,
 66→                updatedAt: item.updatedAt ?? new Date(),
 67→              })),
 68→            }
 69→          : undefined,
 70→      },
 71→      include: { BOMItem: true },
 72→    });
 73→  }
 74→
 75→  /**
 76→   * Find a BOM by ID, optionally including its items
 77→   */
 78→  async findById(id: string, includeItems = false): Promise<BOM | null> {
 79→    return prisma.bOM.findUnique({
 80→      where: { id },
 81→      include: { BOMItem: includeItems },
 82→    });
 83→  }
 84→
 85→  /**
 86→   * Find a BOM by projectId (1-to-1), optionally including its items
 87→   */
 88→  async findByProjectId(
 89→    projectId: string,
 90→    includeItems = false
 91→  ): Promise<BOM | null> {
 92→    return prisma.bOM.findUnique({
 93→      where: { projectId },
 94→      include: { BOMItem: includeItems },
 95→    });
 96→  }
 97→
 98→  /**
 99→   * Update BOM fields. Always sets updatedAt to now.
100→   */
101→  async update(id: string, data: BOMUpdateInput): Promise<BOM> {
102→    return prisma.bOM.update({
103→      where: { id },
104→      data: {
105→        ...data,
106→        updatedAt: new Date(),
107→      },
108→    });
109→  }
110→
111→  /**
112→   * Hard-delete a BOM (cascades to BOMItems)
113→   */
114→  async delete(id: string): Promise<BOM> {
115→    return prisma.bOM.delete({ where: { id } });
116→  }
117→
118→  /**
119→   * Lock a BOM by setting status='locked'
120→   */
121→  async lock(id: string): Promise<BOM> {
122→    return prisma.bOM.update({
123→      where: { id },
124→      data: { status: 'locked', updatedAt: new Date() },
125→    });
126→  }
127→
128→  /**
129→   * Unlock a BOM by setting status='draft'
130→   */
131→  async unlock(id: string): Promise<BOM> {
132→    return prisma.bOM.update({
133→      where: { id },
134→      data: { status: 'draft', updatedAt: new Date() },
135→    });
136→  }
137→
138→  // ─── BOMItem CRUD ────────────────────────────────────────
139→
140→  /**
141→   * Create a single BOMItem
142→   */
143→  async createItem(data: BOMItemCreateInput): Promise<BOMItem> {
144→    return prisma.bOMItem.create({
145→      data: {
146→        ...data,
147→        id: data.id ?? randomUUID(),
148→        updatedAt: data.updatedAt ?? new Date(),
149→      },
150→    });
151→  }
152→
153→  /**
154→   * Find all BOMItems for a given BOM, ordered by rowNumber
155→   */
156→  async findItemsByBomId(bomId: string): Promise<BOMItem[]> {
157→    return prisma.bOMItem.findMany({
158→      where: { bomId },
159→      orderBy: { rowNumber: 'asc' },
160→    });
161→  }
162→
163→  /**
164→   * Update a BOMItem. Always sets updatedAt to now.
165→   */
166→  async updateItem(id: string, data: BOMItemUpdateInput): Promise<BOMItem> {
167→    return prisma.bOMItem.update({
168→      where: { id },
169→      data: {
170→        ...data,
171→        updatedAt: new Date(),
172→      },
173→    });
174→  }
175→
176→  /**
177→   * Delete a single BOMItem
178→   */
179→  async deleteItem(id: string): Promise<BOMItem> {
180→    return prisma.bOMItem.delete({ where: { id } });
181→  }
182→
183→  /**
184→   * Bulk-create BOMItems for a BOM.
185→   * Returns the count of created items.
186→   */
187→  async bulkCreateItems(
188→    bomId: string,
189→    items: (Omit<BOMItemCreateInput, 'bomId'> &
190→      Partial<Pick<BOMItemCreateInput, 'id' | 'updatedAt'>>)[]
191→  ): Promise<number> {
192→    const result = await prisma.bOMItem.createMany({
193→      data: items.map((item, index) => ({
194→        ...item,
195→        id: item.id ?? randomUUID(),
196→        bomId,
197→        rowNumber: item.rowNumber ?? index + 1,
198→        updatedAt: item.updatedAt ?? new Date(),
199→      })),
200→    });
201→    return result.count;
202→  }
203→}
204→
205→/**
206→ * Singleton instance for use across the application
207→ */
208→export const bom = new BOMRepository();
209→
210→export default bom;
