  4→ * TypeScript client for BOM (Bill of Materials) API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on BOM and BOMItem.
  6→ */
  7→import type {
  8→  BOMData,
  9→  BOMItemData,
 10→  BOMListParams,
 11→  BOMCreateInput,
 12→  BOMUpdateInput,
 13→  BOMItemCreateInput,
 14→  BOMItemUpdateInput,
 15→  ApiListResponse,
 16→  ApiResponse,
 17→  ApiClientConfig,
 18→} from './types';
 19→import { ApiClientError, parseApiError, parseJson } from './shared';
 20→
 21→export { ApiClientError } from './shared';
 22→
 23→const DEFAULT_BASE_URL = '/api';
 24→
 25→export class BOMApiClient {
 26→  private baseUrl: string;
 27→  private fetchFn: typeof globalThis.fetch;
 28→  private defaultHeaders: Record<string, string>;
 29→
 30→  constructor(config: ApiClientConfig = {}) {
 31→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 32→    this.fetchFn = config.fetch ?? fetch;
 33→    this.defaultHeaders = {
 34→      'Content-Type': 'application/json',
 35→      ...config.headers,
 36→    };
 37→  }
 38→
 39→  private url(path: string, params?: Record<string, string | undefined>): string {
 40→    const fullUrl = `${this.baseUrl}${path}`;
 41→
 42→    if (params) {
 43→      const searchParams = new URLSearchParams();
 44→      for (const [key, value] of Object.entries(params)) {
 45→        if (value !== undefined) {
 46→          searchParams.append(key, value);
 47→        }
 48→      }
 49→      const queryString = searchParams.toString();
 50→      if (queryString) {
 51→        return `${fullUrl}?${queryString}`;
 52→      }
 53→    }
 54→
 55→    return fullUrl;
 56→  }
 57→
 58→  /**
 59→   * GET /api/bom?projectId=X
 60→   *
 61→   * Fetch BOM for a project. Returns single BOM since projectId is unique.
 62→   */
 63→  async getBOM(projectId: string): Promise<ApiResponse<BOMData>> {
 64→    if (!projectId) {
 65→      throw new ApiClientError(400, 'Validation failed', 'projectId is required');
 66→    }
 67→
 68→    const response = await this.fetchFn(
 69→      this.url('/bom', { projectId }),
 70→      { headers: this.defaultHeaders }
 71→    );
 72→
 73→    if (!response.ok) {
 74→      return parseApiError(response);
 75→    }
 76→
 77→    return parseJson<ApiResponse<BOMData>>(response);
 78→  }
 79→
 80→  /**
 81→   * GET /api/bom/[id]
 82→   *
 83→   * Fetch a single BOM by its ID.
 84→   */
 85→  async getBOMById(id: string): Promise<ApiResponse<BOMData>> {
 86→    if (!id) {
 87→      throw new ApiClientError(400, 'Validation failed', 'id is required');
 88→    }
 89→
 90→    const response = await this.fetchFn(
 91→      this.url(`/bom/${id}`),
 92→      { headers: this.defaultHeaders }
 93→    );
 94→
 95→    if (!response.ok) {
 96→      return parseApiError(response);
 97→    }
 98→
 99→    return parseJson<ApiResponse<BOMData>>(response);
100→  }
101→
102→  /**
103→   * POST /api/bom
104→   *
105→   * Create a new BOM for a project.
106→   */
107→  async createBOM(data: BOMCreateInput): Promise<ApiResponse<BOMData>> {
108→    const response = await this.fetchFn(
109→      this.url('/bom'),
110→      {
111→        method: 'POST',
112→        headers: this.defaultHeaders,
113→        body: JSON.stringify(data),
114→      }
115→    );
116→
117→    if (!response.ok) {
118→      return parseApiError(response);
119→    }
120→
121→    return parseJson<ApiResponse<BOMData>>(response);
122→  }
123→
124→  /**
125→   * PATCH /api/bom/[id]
126→   *
127→   * Update BOM status or sourceFileId.
128→   */
129→  async updateBOM(id: string, data: BOMUpdateInput): Promise<ApiResponse<BOMData>> {
130→    if (!id) {
131→      throw new ApiClientError(400, 'Validation failed', 'id is required');
132→    }
133→
134→    const response = await this.fetchFn(
135→      this.url(`/bom/${id}`),
136→      {
137→        method: 'PATCH',
138→        headers: this.defaultHeaders,
139→        body: JSON.stringify(data),
140→      }
141→    );
142→
143→    if (!response.ok) {
144→      return parseApiError(response);
145→    }
146→
147→    return parseJson<ApiResponse<BOMData>>(response);
148→  }
149→
150→  /**
151→   * DELETE /api/bom/[id]
152→   *
153→   * Delete a BOM and all its items (cascade).
154→   */
155→  async deleteBOM(id: string): Promise<ApiResponse<BOMData> & { message: string }> {
156→    if (!id) {
157→      throw new ApiClientError(400, 'Validation failed', 'id is required');
158→    }
159→
160→    const response = await this.fetchFn(
161→      this.url(`/bom/${id}`),
162→      { method: 'DELETE', headers: this.defaultHeaders }
163→    );
164→
165→    if (!response.ok) {
166→      return parseApiError(response);
167→    }
168→
169→    return parseJson<ApiResponse<BOMData> & { message: string }>(response);
170→  }
171→
172→  /**
173→   * POST /api/bom/[id]/lock
174→   *
175→   * Lock a BOM so it cannot be edited.
176→   */
177→  async lockBOM(id: string): Promise<ApiResponse<BOMData>> {
178→    if (!id) {
179→      throw new ApiClientError(400, 'Validation failed', 'id is required');
180→    }
181→
182→    const response = await this.fetchFn(
183→      this.url(`/bom/${id}/lock`),
184→      { method: 'POST', headers: this.defaultHeaders }
185→    );
186→
187→    if (!response.ok) {
188→      return parseApiError(response);
189→    }
190→
191→    return parseJson<ApiResponse<BOMData>>(response);
192→  }
193→
194→  /**
195→   * POST /api/bom/[id]/unlock
196→   *
197→   * Unlock a BOM to allow edits.
198→   */
199→  async unlockBOM(id: string): Promise<ApiResponse<BOMData>> {
200→    if (!id) {
201→      throw new ApiClientError(400, 'Validation failed', 'id is required');
202→    }
203→
204→    const response = await this.fetchFn(
205→      this.url(`/bom/${id}/unlock`),
206→      { method: 'POST', headers: this.defaultHeaders }
207→    );
208→
209→    if (!response.ok) {
210→      return parseApiError(response);
211→    }
212→
213→    return parseJson<ApiResponse<BOMData>>(response);
214→  }
215→
216→  /**
217→   * GET /api/bom/[bomId]/items
218→   *
219→   * Get all items for a BOM.
220→   */
221→  async getBOMItems(bomId: string): Promise<ApiListResponse<BOMItemData>> {
222→    if (!bomId) {
223→      throw new ApiClientError(400, 'Validation failed', 'bomId is required');
224→    }
225→
226→    const response = await this.fetchFn(
227→      this.url(`/bom/${bomId}/items`),
228→      { headers: this.defaultHeaders }
229→    );
230→
231→    if (!response.ok) {
232→      return parseApiError(response);
233→    }
234→
235→    return parseJson<ApiListResponse<BOMItemData>>(response);
236→  }
237→
238→  /**
239→   * POST /api/bom/[bomId]/items
240→   *
241→   * Add items to a BOM.
242→   */
243→  async addBOMItems(
244→    bomId: string,
245→    items: BOMItemCreateInput[]
246→  ): Promise<ApiListResponse<BOMItemData>> {
247→    if (!bomId) {
248→      throw new ApiClientError(400, 'Validation failed', 'bomId is required');
249→    }
250→
251→    const response = await this.fetchFn(
252→      this.url(`/bom/${bomId}/items`),
253→      {
254→        method: 'POST',
255→        headers: this.defaultHeaders,
256→        body: JSON.stringify({ items }),
257→      }
258→    );
259→
260→    if (!response.ok) {
261→      return parseApiError(response);
262→    }
263→
264→    return parseJson<ApiListResponse<BOMItemData>>(response);
265→  }
266→
267→  /**
268→   * PATCH /api/bom/items/[id]
269→   *
270→   * Update a single BOM item.
271→   */
272→  async updateBOMItem(
273→    id: string,
274→    data: BOMItemUpdateInput
275→  ): Promise<ApiResponse<BOMItemData>> {
276→    if (!id) {
277→      throw new ApiClientError(400, 'Validation failed', 'id is required');
278→    }
279→
280→    const response = await this.fetchFn(
281→      this.url(`/bom/items/${id}`),
282→      {
283→        method: 'PATCH',
